def pinecone_retrieval_tool(query):
    # Vector search implementation
    results = pinecone_index.query(vector=embedding(query), top_k=5)
    return format_docs(results.matches)

@tool
def lookup_order(order_id: str) -> dict:
    """Lookup order status from Stripe/Zendesk"""
    order = stripe.Order.retrieve(order_id)
    ticket = zendesk.tickets.find(order.customer_id)
    return {
        'status': order.status,
        'total': order.amount,
        'tickets': [t.id for t in ticket]
    }

crm_agent = Agent(
    name="CRM Agent",
    instructions="Use tools for order lookup and ticket creation. Always return structured JSON.",
    tools=[lookup_order, create_ticket_tool]
)

